/*Version 2.3, 2023-05-02, MN*/ IF( AND( IsPersonAccount = TRUE, MembershipStatus__c != 'Avliden', MembershipStatus__c != 'Utesluten', MembershipStatus__c != 'Makulerad', ( (MembershipStatus__c = 'Kommande' && ISBLANK(CancellationDate__c)) || (MembershipStatus__c = 'Aktiv' && ISBLANK(CancellationDate__c)) || (MembershipStatus__c = 'Ej medlem' && ISPICKVAL(Type, "Förtroendevald, ej Akavia")) || (MembershipStatus__c = 'Ej medlem' && ISPICKVAL(Type, "Opinionsbildare")) || (MembershipStatus__c = 'Ej medlem' && ISPICKVAL(Type, "Lead")) || (MembershipStatus__c = 'Avslutad' && ISPICKVAL(Type, "Förtroendevald, ej Akavia")) || ( (MembershipStatus__c != 'Aktiv' && MembershipStatus__c != 'Ej medlem' && MembershipStatus__c != 'Kommande') && CancellationDate__c +182 > today() ) ), OR( NOT(ISBLANK(PersonEmail)), NOT(ISBLANK(PersonMobilePhone)) ) ), TRUE, FALSE)
